-- Backfill full 5-language (en/cs/sk/uk/ru) Translations for every seeded Service and Package.
--
-- Why: the mobile + web apps render service/package names via translations[lang].Name with an English
-- fallback. The seed historically carried only en/cs/ru (and some live DEV rows were created with empty
-- Translations), so Slovak/Ukrainian users — and any row missing its language — saw the English fallback.
-- This backfills sk + uk (and re-asserts en/cs/ru) so all five languages resolve.
--
-- Idempotent: matches rows by their English "Name" and overwrites "Translations" with the full map, so it
-- is safe to re-run. Apply to the DEV database (the seed below is also updated for fresh installs).
-- Slovak derived from the Czech copy, Ukrainian from the Russian copy.

BEGIN;

-- ===== Services =====
UPDATE public."Services" SET "Translations" = '{"en":{"Name":"General Cleaning","Description":"Standard cleaning of all rooms including dusting, vacuuming, and sanitizing"},"cs":{"Name":"Obecný úklid","Description":"Standardní úklid všech místností včetně otírání prachu, vysávání a dezinfekce"},"sk":{"Name":"Všeobecné upratovanie","Description":"Štandardné upratovanie všetkých miestností vrátane utierania prachu, vysávania a dezinfekcie"},"uk":{"Name":"Загальне прибирання","Description":"Стандартне прибирання всіх кімнат, включно з витиранням пилу, пилососом та дезінфекцією"},"ru":{"Name":"Общая уборка","Description":"Стандартная уборка всех комнат включая протирание пыли, пылесос и дезинфекцию"}}' WHERE "Name" = 'General Cleaning';

UPDATE public."Services" SET "Translations" = '{"en":{"Name":"Deep Cleaning","Description":"Thorough cleaning including baseboards, inside appliances, and detailed sanitization"},"cs":{"Name":"Hloubkový úklid","Description":"Důkladný úklid včetně lišt, vnitřků spotřebičů a detailní dezinfekce"},"sk":{"Name":"Hĺbkové upratovanie","Description":"Dôkladné upratovanie vrátane líšt, vnútra spotrebičov a detailnej dezinfekcie"},"uk":{"Name":"Глибоке прибирання","Description":"Ретельне прибирання, включно з плінтусами, всередині побутової техніки та детальною дезінфекцією"},"ru":{"Name":"Глубокая уборка","Description":"Тщательная уборка включая плинтуса, внутри бытовой техники и детальная дезинфекция"}}' WHERE "Name" = 'Deep Cleaning';

UPDATE public."Services" SET "Translations" = '{"en":{"Name":"Bathroom Cleaning","Description":"Specialized bathroom cleaning with tile scrubbing and grout cleaning"},"cs":{"Name":"Úklid koupelny","Description":"Specializovaný úklid koupelny s drhnáním dlaždic a čištěním spár"},"sk":{"Name":"Upratovanie kúpeľne","Description":"Špecializované upratovanie kúpeľne s drhnutím dlaždíc a čistením škár"},"uk":{"Name":"Прибирання ванної","Description":"Спеціалізоване прибирання ванної з чищенням плитки та швів"},"ru":{"Name":"Уборка ванной","Description":"Специализированная уборка ванной с чисткой плитки и швов"}}' WHERE "Name" = 'Bathroom Cleaning';

